import{_ as i,o as a,c as e,ah as r}from"./chunks/framework.BvDvRtye.js";const u=JSON.parse('{"title":"通信链路","description":"","frontmatter":{},"headers":[],"relativePath":"basic/network/netlink.md","filePath":"basic/network/netlink.md"}'),p={name:"basic/network/netlink.md"};function n(h,l,o,t,s,c){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="通信链路" tabindex="-1">通信链路 <a class="header-anchor" href="#通信链路" aria-label="Permalink to “通信链路”">​</a></h1><h1 id="通信链路分析与协议分层" tabindex="-1">通信链路分析与协议分层 <a class="header-anchor" href="#通信链路分析与协议分层" aria-label="Permalink to “通信链路分析与协议分层”">​</a></h1><h2 id="一、从-链路类型-到-协议分层-的视角" tabindex="-1">一、从“链路类型”到“协议分层”的视角 <a class="header-anchor" href="#一、从-链路类型-到-协议分层-的视角" aria-label="Permalink to “一、从“链路类型”到“协议分层”的视角”">​</a></h2><p>原文按照物理拓扑划分为：机内通信、卡间通信、机间通信。这是<strong>部署视角</strong>。</p><p>如果换成通信工程视角，我们会关心：</p><ul><li>物理层（Physical Layer）</li><li>数据链路层（Data Link Layer）</li><li>传输层 / 互联层</li><li>协议语义层（例如 RDMA、Collective 通信语义）</li><li>分布式框架层（NCCL / MPI / Megatron 等）</li></ul><p>不同链路技术，其实是在不同层做创新。</p><hr><h2 id="二、物理层-电信号、serdes-与带宽的本质" tabindex="-1">二、物理层：电信号、SerDes 与带宽的本质 <a class="header-anchor" href="#二、物理层-电信号、serdes-与带宽的本质" aria-label="Permalink to “二、物理层：电信号、SerDes 与带宽的本质”">​</a></h2><p>物理层关注的核心问题只有三个：</p><ul><li>比特如何在铜线 / 光纤上传输</li><li>信号速率是多少（GT/s）</li><li>每条链路有多少 lane</li></ul><p>例如：</p><ul><li>PCIe 5.0：32 GT/s 每 lane，x16 形成总带宽</li><li>NVLink：采用专用 SerDes 通道</li><li>InfiniBand：HDR / NDR 代表不同物理编码速率</li></ul><p>“带宽”本质上是：</p><p>带宽 ≈ 单 lane 速率 × lane 数 × 编码效率</p><p>延迟则与：</p><ul><li>物理距离</li><li>SerDes 编解码延迟</li><li>交换芯片转发深度</li></ul><p>有关。</p><p>关键洞察：</p><p>PCIe、CXL、NVLink 在物理层都是高速串行差分信号 + SerDes，本质差别不在电信号，而在协议层。</p><hr><h2 id="三、数据链路层-可靠传输与流控" tabindex="-1">三、数据链路层：可靠传输与流控 <a class="header-anchor" href="#三、数据链路层-可靠传输与流控" aria-label="Permalink to “三、数据链路层：可靠传输与流控”">​</a></h2><p>这一层负责：</p><ul><li>CRC 校验</li><li>重传机制</li><li>Flow Control（信用机制）</li></ul><p>例如：</p><ul><li>PCIe 使用 credit-based flow control</li><li>InfiniBand 使用基于 VL（Virtual Lane）的流控</li><li>以太网依赖 MAC + PFC（Priority Flow Control）实现无损</li></ul><p>RoCE 之所以复杂，是因为它在以太网上模拟 InfiniBand 的无损语义。</p><p>如果网络丢包，RDMA 语义就会崩溃。</p><p>所以 RoCE 依赖：</p><ul><li>PFC（防止丢包）</li><li>ECN（拥塞标记）</li></ul><p>这就是协议层“语义依赖物理行为”的典型例子。</p><hr><h2 id="四、互联协议层-内存语义-vs-消息语义" tabindex="-1">四、互联协议层：内存语义 vs 消息语义 <a class="header-anchor" href="#四、互联协议层-内存语义-vs-消息语义" aria-label="Permalink to “四、互联协议层：内存语义 vs 消息语义”">​</a></h2><p>这是本文的关键技术点。</p><p>通信可以分成两种模型：</p><ol><li>消息传递模型（Message Passing）</li><li>共享内存模型（Shared Memory Semantics）</li></ol><h3 id="_1️⃣-消息模型" tabindex="-1">1️⃣ 消息模型 <a class="header-anchor" href="#_1️⃣-消息模型" aria-label="Permalink to “1️⃣ 消息模型”">​</a></h3><p>典型代表：</p><ul><li>TCP/IP</li><li>MPI</li></ul><p>特点：</p><ul><li>发送 send()</li><li>接收 recv()</li><li>CPU 参与协议栈处理</li></ul><h3 id="_2️⃣-内存语义模型" tabindex="-1">2️⃣ 内存语义模型 <a class="header-anchor" href="#_2️⃣-内存语义模型" aria-label="Permalink to “2️⃣ 内存语义模型”">​</a></h3><p>典型代表：</p><ul><li>RDMA</li><li>CXL.mem</li><li>NVLink peer memory</li></ul><p>特点：</p><ul><li>直接读写远程内存</li><li>CPU 不参与数据路径</li><li>Zero-copy</li></ul><p>RDMA 的本质不是“快”，而是绕过远端 CPU 协议栈。</p><p>这就是所谓 kernel bypass。</p><p>这也是为什么 InfiniBand 延迟能做到 ~1 μs。</p><hr><h2 id="五、缓存一致性层-cxl-的突破" tabindex="-1">五、缓存一致性层：CXL 的突破 <a class="header-anchor" href="#五、缓存一致性层-cxl-的突破" aria-label="Permalink to “五、缓存一致性层：CXL 的突破”">​</a></h2><p>CXL.cache / CXL.mem 引入了 cache coherency。</p><p>这意味着：</p><p>CPU cache line 可以与 GPU cache line 保持一致。</p><p>这是比 RDMA 更高级的语义：</p><p>RDMA 是远程内存访问。</p><p>CXL 是远程 cache 访问。</p><p>这会改变系统架构，例如：</p><ul><li>内存池化</li><li>内存扩展</li><li>设备共享页表</li></ul><p>如果你熟悉 NUMA，本质上 CXL 在做“跨设备 NUMA”。</p><hr><h2 id="六、交换结构-拓扑与带宽放大" tabindex="-1">六、交换结构：拓扑与带宽放大 <a class="header-anchor" href="#六、交换结构-拓扑与带宽放大" aria-label="Permalink to “六、交换结构：拓扑与带宽放大”">​</a></h2><p>NVSwitch、InfiniBand Switch 的作用是：</p><ul><li>构建 Clos / Fat-tree / Ring / Mesh 拓扑</li><li>放大 bisection bandwidth（双向切分带宽）</li></ul><p>环形拓扑的带宽利用率高，但延迟叠加。</p><p>全连接拓扑延迟最低，但成本指数增长。</p><p>Google TPU Pod 的 ICI 使用 2D mesh，本质上是平衡成本与带宽。</p><p>这是拓扑学与通信工程的结合。</p><hr><h2 id="七、从硬件到框架-通信抽象层" tabindex="-1">七、从硬件到框架：通信抽象层 <a class="header-anchor" href="#七、从硬件到框架-通信抽象层" aria-label="Permalink to “七、从硬件到框架：通信抽象层”">​</a></h2><p>硬件之上还有软件抽象层：</p><ul><li>NCCL（GPU 集合通信）</li><li>MPI（分布式通信）</li><li>Gloo</li><li>OneCCL</li></ul><p>它们实现：</p><ul><li>AllReduce</li><li>AllGather</li><li>Broadcast</li><li>ReduceScatter</li></ul><p>这些集合操作的复杂度与拓扑相关：</p><p>Ring AllReduce：O(N) Tree AllReduce：O(log N)</p><p>Megatron 的 3D 并行，其实是把不同通信频率映射到不同物理层。</p><p>这是“算法感知硬件”。</p><hr><h2 id="八、通信墙的物理本质" tabindex="-1">八、通信墙的物理本质 <a class="header-anchor" href="#八、通信墙的物理本质" aria-label="Permalink to “八、通信墙的物理本质”">​</a></h2><p>所谓 communication wall，本质是：</p><p>计算增长 ~ O(N) 通信增长 ~ O(N log N) 或 O(N^2)</p><p>当 GPU 数量增加，</p><ul><li>参数同步量线性增长</li><li>拓扑拥塞指数增长</li></ul><p>物理层无法无限扩展。</p><p>光模块功耗、交换芯片端口密度、电源限制都会成为瓶颈。</p><p>这就是为什么下一代互联开始使用：</p><ul><li>硅光（Silicon Photonics）</li><li>光互连背板</li><li>Chiplet 封装内互联</li></ul><p>计算正在向“光速墙”逼近。</p><hr><h2 id="九、分层总结-从下到上" tabindex="-1">九、分层总结（从下到上） <a class="header-anchor" href="#九、分层总结-从下到上" aria-label="Permalink to “九、分层总结（从下到上）”">​</a></h2><ol><li>物理层：SerDes、电气信号、光模块</li><li>数据链路层：流控、重传</li><li>传输语义层：消息 vs 内存语义（TCP vs RDMA）</li><li>一致性层：Cache coherency（CXL）</li><li>拓扑层：Ring / Mesh / Fat-tree</li><li>集合通信层：NCCL / MPI</li><li>分布式训练策略层：数据并行 / 张量并行 / 流水线并行</li></ol><p>原文主要讨论的是第 1、3、5 层。</p><p>补充之后，可以看到通信系统是一个跨越电气工程、体系结构、操作系统和分布式算法的综合工程。</p><p>真正的优化不是“换一张更快的网卡”，而是理解整条分层栈的瓶颈在哪里。</p>',95)])])}const C=i(p,[["render",n]]);export{u as __pageData,C as default};
